import jsPDF from 'jspdf'
import type { ProposalSection } from './proposal-types'

// Logo da Wa Project - versão hexagonal conforme HTML template
const WA_PROJECT_LOGO_BASE64 = `data:image/svg+xml;base64,`

// Cores extraídas do PDF oficial Wa Project
const WA_COLORS = {
  blue: '#1E5B96', // Azul exato do PDF oficial
  text: '#333333', // Texto principal escuro
  textMuted: '#666666', // Texto secundário
